// ---- Step 1: extract email metadata + keep attachments as binary ----
const j = $json;
const parseAddr = (s) => {
  if (!s) return { name: '', email: '' };
  const m = String(s).match(/^\s*"?([^"<]*)"?\s*<([^>]+)>\s*$/);
  if (m) return { name: m[1].trim(), email: m[2].trim().toLowerCase() };
  return { name: '', email: String(s).trim().toLowerCase() };
};
const fromRaw = (j.from && j.from.value && j.from.value[0])
  ? { name: j.from.value[0].name || '', email: String(j.from.value[0].address || '').toLowerCase() }
  : parseAddr((j.from && j.from.text) || (j.headers && j.headers.from) || j.From || '');
let body = j.text || j.textPlain || '';
if (!body && (j.html || j.textHtml)) {
  body = String(j.html || j.textHtml)
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
const binary = $input.item.binary || {};
return {
  json: {
    senderName: fromRaw.name,
    senderEmail: fromRaw.email,
    subject: j.subject || (j.headers && j.headers.subject) || '(no subject)',
    body: body,
    bodyForAI: body.slice(0, 8000),
    messageId: String(j.id || j.messageId || ''),
    threadId: String(j.threadId || ''),
    receivedAt: j.date ? new Date(j.date).toISOString() : new Date().toISOString(),
    attachmentNames: Object.values(binary).map(b => b.fileName || 'file').join(', ') || 'none',
  },
  binary: binary,
};

// ---- Step 2: build the LLM request (system prompt lives here) ----
const e = $('Extract Metadata').item.json;
const system = `You are a support-ticket triage engine for a SaaS company. You receive one
customer support email and return ONLY a single valid JSON object - no
markdown fences, no commentary, no keys other than those specified.

Output schema (all keys required; use null when unknown, never invent facts):
{
  "customer_name": string | null,
  "company": string | null,
  "issue_summary": string,            // max 2 sentences, plain language
  "detailed_description": string,
  "category": one of ["Technical Support","Billing","Sales Inquiry","Feature Request","Bug Report","Account Access","Refund Request","General Inquiry"],
  "priority": one of ["Critical","High","Medium","Low"],
  "priority_justification": string,   // 1 sentence citing evidence
  "sentiment": one of ["Positive","Neutral","Negative"],
  "product": string | null,
  "suggested_department": one of ["Technical Support","Finance","Sales","Customer Success","Product Team"],
  "suggested_tags": string[],         // 2-5 lowercase kebab-case tags
  "confidence_score": number          // 0.0-1.0 certainty in category+priority
}

Classification rules:
- Bug Report = something is broken/erroring; Technical Support = help using a working feature; Account Access = login, password, 2FA, lockout.
- Refund Request only when the customer explicitly asks for money back; otherwise billing disputes are Billing.

Priority rules (apply the highest that matches):
- Critical: production outage, all users blocked, data loss, security incident, payment system down.
- High: core feature broken for the customer, blocked workflow, explicit urgent deadline, legal/compliance threat, threat to cancel.
- Medium: degraded experience with a workaround, billing questions, access issues for a single user.
- Low: general questions, feature requests, feedback, sales inquiries.

Sentiment reflects the customer's tone, not the issue severity.
Lower confidence_score when the email is ambiguous, multi-issue, or in a language you had to translate.
If the email is spam or not a support request, use category "General Inquiry", priority "Low", and tag "possible-spam".`;
const user = `Analyze this support email.\n\nSENDER NAME: ${e.senderName}\nSENDER EMAIL: ${e.senderEmail}\nSUBJECT: ${e.subject}\nRECEIVED: ${e.receivedAt}\nATTACHMENTS: ${e.attachmentNames}\n\nBODY:\n"""\n${e.bodyForAI}\n"""`;
return {
  json: {
    requestBody: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0,
      max_tokens: 1024,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user },
      ],
    },
  },
};

// ---- Step 5: validate & normalize AI output (must never throw) ----
const CATEGORIES = ["Technical Support","Billing","Sales Inquiry","Feature Request","Bug Report","Account Access","Refund Request","General Inquiry"];
const PRIORITIES = ["Critical","High","Medium","Low"];
const SENTIMENTS = ["Positive","Neutral","Negative"];
const DEPARTMENTS = ["Technical Support","Finance","Sales","Customer Success","Product Team"];
const TEAM_MAP = {
  "Technical Support": "Technical Support",
  "Bug Report": "Technical Support",
  "Account Access": "Technical Support",
  "Billing": "Finance",
  "Refund Request": "Finance",
  "Sales Inquiry": "Sales",
  "Feature Request": "Product Team",
  "General Inquiry": "Customer Success",
};
const SLA_HOURS = { Critical: 2, High: 4, Medium: 24, Low: 48 };

const email = $('Extract Metadata').item.json;
const raw = $json;

function safeParse(text) {
  if (text && typeof text === 'object') return text;
  if (typeof text !== 'string') return null;
  let t = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '');
  try { return JSON.parse(t); } catch (_) {}
  const m = t.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch (_) {} }
  return null;
}
// Groq/Mistral are OpenAI-compatible: text lives at choices[0].message.content
const aiText = (raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content) || raw.text || raw.output || raw;
let ai = safeParse(aiText);

let needsReview = false;
const notes = [];
if (!ai) { ai = {}; needsReview = true; notes.push('AI response unparseable - defaults applied'); }
if (ai && !ai.issue_summary && !ai.category) { ai = {}; needsReview = true; notes.push('AI output missing required keys - defaults applied'); }

function normalizeEnum(value, allowed, fallback) {
  if (typeof value !== 'string') { needsReview = true; return fallback; }
  const v = value.trim().toLowerCase();
  const hit = allowed.find(a => a.toLowerCase() === v)
           || allowed.find(a => a.toLowerCase().includes(v) || v.includes(a.toLowerCase()));
  if (!hit) { needsReview = true; notes.push(`Unknown value "${value}" -> "${fallback}"`); }
  return hit || fallback;
}
const category = normalizeEnum(ai.category, CATEGORIES, 'General Inquiry');
let priority = normalizeEnum(ai.priority, PRIORITIES, 'Medium');
const sentiment = normalizeEnum(ai.sentiment, SENTIMENTS, 'Neutral');
const suggestedDept = normalizeEnum(ai.suggested_department, DEPARTMENTS, 'Customer Success');

// Business-rule priority overrides (never let AI downgrade these)
const bodyLC = `${email.subject} ${email.body}`.toLowerCase();
const ruleHits = [];
if (/\b(outage|down for everyone|data loss|security breach|hacked|cannot process payments)\b/.test(bodyLC)) {
  if (priority !== 'Critical') ruleHits.push(`rule: critical keyword -> Critical (was ${priority})`);
  priority = 'Critical';
} else if (/\b(urgent|asap|immediately|escalate|cancel(?:ling)? (?:my|our) (?:account|subscription))\b/.test(bodyLC)
           && (priority === 'Medium' || priority === 'Low')) {
  ruleHits.push(`rule: urgency keyword -> High (was ${priority})`);
  priority = 'High';
}

// Tags: coerce, lowercase, kebab, dedupe, cap at 5
let tags = Array.isArray(ai.suggested_tags) ? ai.suggested_tags
         : typeof ai.suggested_tags === 'string' ? ai.suggested_tags.split(',') : [];
tags = [...new Set(
  tags.map(t => String(t).trim().toLowerCase().replace(/\s+/g, '-'))
      .filter(t => t.length > 0 && t.length <= 40)
)].slice(0, 5);

// Email validation
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;
const senderEmail = EMAIL_RE.test(email.senderEmail || '') ? email.senderEmail : null;
if (!senderEmail) { needsReview = true; notes.push('Invalid sender email - ack will be skipped'); }

let confidence = Number(ai.confidence_score);
if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) confidence = 0.5;
if (confidence < 0.6) { needsReview = true; notes.push(`Low confidence ${confidence}`); }

const customerName = (ai.customer_name || email.senderName || 'Unknown').toString().slice(0, 100);
const summary = (ai.issue_summary || email.subject || 'No summary available').toString().slice(0, 500);

return {
  json: {
    ticketId: `TKT-${Date.now().toString(36).toUpperCase()}-${Math.random().toString(36).slice(2, 6).toUpperCase()}`,
    customerName,
    company: ai.company || '',
    senderEmail: senderEmail || email.senderEmail || '',
    validEmail: !!senderEmail,
    subject: email.subject || '(no subject)',
    body: email.body || '',
    issueSummary: summary,
    detailedDescription: ai.detailed_description || summary,
    category, priority, sentiment,
    priorityJustification: [ai.priority_justification, ...ruleHits].filter(Boolean).join(' | '),
    product: ai.product || '',
    suggestedDepartment: suggestedDept,
    tags,
    confidence,
    needsReview,
    validationNotes: notes.join('; '),
    assignedTeam: TEAM_MAP[category] || 'Triage',
    slaHours: SLA_HOURS[priority],
    status: 'Open',
    messageId: email.messageId,
    threadId: email.threadId,
    receivedAt: email.receivedAt,
  },
};

// ---- Prep attachments for Airtable content upload (base64, <=5MB) ----
const out = [];
const created = $input.all();
const metas = $('Extract Metadata').all();
for (let i = 0; i < created.length; i++) {
  const recordId = created[i].json.id;
  const bin = (metas[i] && metas[i].binary) || {};
  for (const key of Object.keys(bin)) {
    const b = bin[key];
    if (!b || !b.data) continue; // filesystem-mode binary not supported by this simple path
    if (Buffer.from(b.data, 'base64').length > 5 * 1024 * 1024) continue; // Airtable free-tier limit
    out.push({ json: { recordId, contentType: b.mimeType || 'application/octet-stream', filename: b.fileName || key, file: b.data } });
  }
}
return out; // empty array = no attachments, downstream node simply does not run
